import{c as a,S as r,j as t,m as l}from"./chunks/framework.DvQr6YbT.js";const u=JSON.parse('{"title":"分享知识","description":"","frontmatter":{},"headers":[],"relativePath":"zh/sharing/index.md","filePath":"zh/sharing/index.md","lastUpdated":1783418049000}'),o={name:"zh/sharing/index.md"};function n(i,e,s,d,c,h){return r(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="分享知识" tabindex="-1">分享知识 <a class="header-anchor" href="#分享知识" aria-label="Permalink to “分享知识”">​</a></h1><p>Knowlery 把经过审核的知识打包成<strong>知识包（bundle）</strong>——密封的、带版本号的制品， 任何 vault 都可以安装。分享是一段由多个独立步骤组成的旅程，最重要的认知是： <strong>这些步骤是彼此分开的</strong>：</p><ol><li><strong>导出与审核</strong>——选定一个种子主题；范围内的每一页、每份原始来源都需要你逐条 显式批准（未经审核的内容绝不出库）。</li><li><strong><a href="./publish">发布</a></strong>——<code>knowlery bundle publish</code> 在你配置的仓库里创建 GitHub Release，并交回一条可直接转发的完整消息（URL、校验和、受众）。默认私有；公开 目标要过第二道门。</li><li><strong><a href="./grant-access">授权</a></strong>——发布<strong>不等于</strong>别人能访问。谁能安装取决于它放在 哪里：公开托管（任何人）、私有仓库（collaborator 或组织成员）、或你直接发送的 文件。</li><li><strong>安装</strong>——<a href="./install-from-url">从 URL 安装</a>或从本地文件安装。</li><li><strong><a href="./subscribe-update">订阅与更新</a></strong>——<code>check-updates</code> 向每个知识包的来源询问 新版本；<code>update</code> 经同样的门安装它们。拉取制,本地修改受保护。</li></ol><h2 id="团队推荐配置-组织货架" tabindex="-1">团队推荐配置：组织货架 <a class="header-anchor" href="#团队推荐配置-组织货架" aria-label="Permalink to “团队推荐配置：组织货架”">​</a></h2><p>团队分享时，在你们的 GitHub 组织下建一个私有仓库——例如 <code>your-org/kb-bundles</code>—— 并把组织的 base permission 设为 <strong>Read</strong>。</p><ul><li>每位成员都能用自己的 GitHub 登录从它的 Release 链接安装。</li><li>权限跟随成员身份：入组即获得，离组即失效。无需逐人逐包管理。</li><li>团队里任何人都可以向同一货架发布自己的知识包——它自然成为团队知识中心。</li></ul><p>GitHub 免费版即可（私有仓库和成员数均不限）。需要更细粒度时用 GitHub 的 team 配置——Knowlery 自身永远不管理权限。</p><h2 id="安全姿态" tabindex="-1">安全姿态 <a class="header-anchor" href="#安全姿态" aria-label="Permalink to “安全姿态”">​</a></h2><ul><li>知识包只包含<strong>你逐条批准过的内容</strong>——绝不会整库打包。</li><li>Knowlery <strong>从不存储或索要 token</strong>。私有来源通过你自己的 <code>gh</code> CLI 登录或浏览器 会话访问。</li><li>如果分享者在链接旁附了校验和，请校验下载： <code>knowlery bundle install &lt;url&gt; --verify &lt;sha256&gt;</code>。</li></ul>',9)])])}const p=a(o,[["render",n]]);export{u as __pageData,p as default};
